SELECT Item.[Season Code], Item.[Trademark Code], Item.[Budget Type], Item.[Collection Code], Item.[Line Code], Item_1.No_, IIf(IsNull([prezziacquisto].[no_]),"",[prezziacquisto.Currency Code]) AS CurrencyCode, Avg(IIf(IsNull([prezziacquisto].[no_]),0,[prezziacquisto.PurchasePrice])) AS PurchPrice, Item_1.Description, Item_1.[Description 2], Item.[Description 6], Item.[Variable Code 01] AS ColorCode, [Variable Code].Description AS ColorDescription, Item.[Carry Over], Item.[Future Carry Over], Item.Smu, Item.[Location Code], Item.[Delivery Period], Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Tariff No_], Val([Item.Unit Volume]) AS UnitVolume, Val([Item.Gross Weight]) AS [GrossWeight(g)], Val([Item.Net Weight]) AS [NetWeight(g)], Val([Item.Height]) AS [Height(cm)], Val([Item.Width]) AS [Width(cm)], Val([Item.Depth]) AS [Depth(cm)], Val([Item.Standard Cost]) AS StandardCost, Item.[Country_Region of Origin Code], Item.[Vendor No_], Vendor.Name, Item.[Potential Sold Out], Item.[Sold Out], Item.[Sold Out Date], Item.[Commission Group Code], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Upper Composition], Item.[Lining Composition], Item.[Outsole Composition], Item.[Advertising Material]
FROM (((Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_) INNER JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) LEFT JOIN PrezziAcquisto ON Item.No_ = PrezziAcquisto.No_
GROUP BY Item.[Season Code], Item.[Trademark Code], Item.[Budget Type], Item.[Collection Code], Item.[Line Code], Item_1.No_, IIf(IsNull([prezziacquisto].[no_]),"",[prezziacquisto.Currency Code]), Item_1.Description, Item_1.[Description 2], Item.[Description 6], Item.[Variable Code 01], [Variable Code].Description, Item.[Carry Over], Item.[Future Carry Over], Item.Smu, Item.[Location Code], Item.[Delivery Period], Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Tariff No_], Val([Item.Unit Volume]), Val([Item.Gross Weight]), Val([Item.Net Weight]), Val([Item.Height]), Val([Item.Width]), Val([Item.Depth]), Val([Item.Standard Cost]), Item.[Country_Region of Origin Code], Item.[Vendor No_], Vendor.Name, Item.[Potential Sold Out], Item.[Sold Out], Item.[Sold Out Date], Item.[Commission Group Code], Item.[Sales_Purchase Status - Item], Item.[Sales_Purchase Status Date], Item.[Upper Composition], Item.[Lining Composition], Item.[Outsole Composition], Item.[Advertising Material], Item.[Configurator Relation]
HAVING (((Item.[Season Code])=[forms]![principale]![FiltroStagioneEAN]) AND ((Item.[Configurator Relation])=3))
ORDER BY Item.[Trademark Code], Item.[Collection Code], Item.[Line Code], Item_1.No_;

